from collections import defaultdict

def solve(nums: list[int], queries: list[list[int]]) -> list[int]:
    ans = []
    for l, r, threshold in queries:
        freq = defaultdict(int)
        max_freq = -1
        candidate = -1
        for num in nums[l: r+1]:
            freq[num] += 1
        for num, count in freq.items():
            if count >= threshold:
                if count > max_freq:
                    max_freq = count
                    candidate = num
                elif count == max_freq:
                    if num < candidate:
                        candidate = num
        ans.append(candidate)
    return ans
